import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatWithHeaderTest {

    private enum TestEnum {
        FIRST, SECOND, THIRD
    }

    @Test
    void testWithHeader_NullEnum_ReturnsFormatWithNullHeader() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat result = baseFormat.withHeader((Class<? extends Enum<?>>) null);
        assertNotNull(result);
        assertNull(result.getHeader());
        assertNotSame(baseFormat, result);
    }

    @Test
    void testWithHeader_EmptyEnum_ReturnsFormatWithEmptyHeader() {
        enum EmptyEnum {}
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat result = baseFormat.withHeader(EmptyEnum.class);
        assertNotNull(result);
        String[] header = result.getHeader();
        assertNotNull(header);
        assertEquals(0, header.length);
        assertNotSame(baseFormat, result);
    }

    @Test
    void testWithHeader_EnumWithValues_ReturnsFormatWithHeaderNames() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat result = baseFormat.withHeader(TestEnum.class);
        assertNotNull(result);
        String[] header = result.getHeader();
        assertNotNull(header);
        assertArrayEquals(new String[] { "FIRST", "SECOND", "THIRD" }, header);
        assertNotSame(baseFormat, result);
    }

    @Test
    void testWithHeader_PrivateMethodInvocation() throws Exception {
        // Using reflection to invoke private withHeader(String[]) method
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        Method withHeaderMethod = CSVFormat.class.getDeclaredMethod("withHeader", String[].class);
        withHeaderMethod.setAccessible(true);

        String[] headers = new String[] { "A", "B", "C" };
        CSVFormat result = (CSVFormat) withHeaderMethod.invoke(baseFormat, (Object) headers);

        assertNotNull(result);
        assertArrayEquals(headers, result.getHeader());
        assertNotSame(baseFormat, result);
    }
}
